#nullable enable // autogenerated  

using MVZ2.GameContent.Buffs.Entities;
using MVZ2.GameContent.Buffs.Level;
using MVZ2.GameContent.Damages;
using MVZ2.Vanilla;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2Logic.Definitions;
using MVZ2Logic.HeldItems;
using MVZ2Logic.Inputs;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Damages;
using PVZEngine.Entities;
using PVZEngine.Level;
using PVZEngine.Buffs;

namespace MVZ2.GameContent.HeldItems
{
    [AutoHeldItemBehaviourDefinition(VanillaHeldItemBehaviourNames.digEnemy)]
    public class DigEnemyHeldItemBehaviour : HeldItemBehaviourDefinition
    {
        public DigEnemyHeldItemBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        public override HeldTargetFlag GetHeldTargetMask(LevelEngine level)
        {
            return HeldTargetFlag.Enemy;
        }
        public override bool IsValidFor(IHeldItemTarget target, IHeldItemData data, PointerInteractionData pointerInteraction)
        {
            var pointer = pointerInteraction.pointer;
            switch (target)
            {
                case HeldItemTargetEntity entityTarget:
                    return CanUseOnEntity(entityTarget.Target);
            }
            return false;
        }
        public override HeldHighlight GetHighlight(IHeldItemTarget target, IHeldItemData data, PointerInteractionData pointer)
        {
            switch (target)
            {
                case HeldItemTargetEntity entityTarget:
                    {
                        var entity = entityTarget.Target;
                        return HeldHighlight.Entity(entity);
                    }
            }
            return HeldHighlight.None;
        }
        public override void OnPointerEvent(IHeldItemTarget target, IHeldItemData data, PointerInteractionData pointerParams)
        {
            if (pointerParams.IsInvalidClickButton())
                return;
            OnMainPointerEvent(target, data, pointerParams);
        }
        private void OnMainPointerEvent(IHeldItemTarget target, IHeldItemData data, PointerInteractionData pointerParams)
        {
            switch (target)
            {
                case HeldItemTargetEntity entityTarget:
                    OnPointerEventEntity(entityTarget, data, pointerParams);
                    break;
            }
        }
        private void OnPointerEventEntity(HeldItemTargetEntity target, IHeldItemData data, PointerInteractionData pointerParams)
        {
            if (pointerParams.IsInvalidReleaseAction())
                return;
            var entity = target.Target;
            entity.Level.ResetHeldItem();
            UseOnEntity(entity);
        }
        private bool CanUseOnEntity(Entity entity)
        {
            if (!entity.ExistsAndAlive() || entity.NoHeldTarget() || entity.CannotDig())
                return false;
            return entity.Type == EntityTypes.ENEMY && entity.CanBeKilledByPickaxe();
        }
        private void UseOnEntity(Entity entity)
        {
            // Die 之前记录：是否石化 + 冷却时长  
            bool wasPetrified = entity.HasBuff<PetrifiedBuff>();
            int cooldownFrames = wasPetrified ? GetPickaxeCooldown(entity) : 0;

            DamageEffectList effects = new DamageEffectList(VanillaDamageEffects.PICKAXE);
            entity.Die(effects);
            if (entity.Level.IsPickaxeCountLimited())
            {
                entity.Level.AddPickaxeRemainCount(-1);
            }

            // 敲碎石化敌人后，让镐子进入冷却  
            if (wasPetrified)
            {
                var buff = entity.Level.AddBuff<StoneEyePickaxeCooldownBuff>();
                if (buff != null)
                    StoneEyePickaxeCooldownBuff.SetTimeout(buff, cooldownFrames);
            }
        }

        // 按被敲碎敌人的分类返回不同的镐子禁用帧数  
        private static int GetPickaxeCooldown(Entity entity)
        {
            int baseFrames = StoneEyePickaxeCooldownBuff.MAX_TIMEOUT;
            var category = entity.GetProperty<NamespaceID>(VanillaEntityProps.CATEGORY);
            // 例：突变类/载具类冷却更长（x2），其余默认  
            if (category == MutantCategory || category == VehicleCategory)
                return baseFrames * 2;
            return baseFrames;
        }

        private static readonly NamespaceID MutantCategory = new NamespaceID(VanillaMod.spaceName, "Mutant_Exp");
        private static readonly NamespaceID VehicleCategory = new NamespaceID(VanillaMod.spaceName, "Vehicle_Exp");
    }
}
